const express = require('express');
const crypto = require('crypto');
const { OAuth2Client } = require('google-auth-library');
const { google } = require('googleapis');
const app = express();
const PORT = process.env.PORT || 3000;
const SHEET_ID = process.env.GOOGLE_SHEET_ID || '1rqFvFG7DGSQS1oQzbZyOx9gUGu7jwiGcoCFlemsBMJw';
const GID = process.env.GOOGLE_SHEET_GID || '0';
const CLIENT_ID = process.env.GOOGLE_CLIENT_ID || '';
const ADMIN_EMAIL = (process.env.ADMIN_EMAIL || '').toLowerCase();
const SESSION_SECRET = process.env.SESSION_SECRET || '';
const ACCESS_TAB = process.env.ACCESS_SHEET_TAB || 'Access Control';
const SESSION_MAX_AGE = 30 * 24 * 60 * 60;
const ICON_192_BASE64 = '';
const ICON_512_BASE64 = '';
const oauth = new OAuth2Client(CLIENT_ID);
app.disable('x-powered-by');
app.use(express.json({limit:'32kb'}));

function sheetsClient(){const key=(process.env.GOOGLE_PRIVATE_KEY||'').replace(/\\n/g,'\n');if(!process.env.GOOGLE_SERVICE_ACCOUNT_EMAIL||!key)throw Error('Google service account is not configured');const auth=new google.auth.JWT({email:process.env.GOOGLE_SERVICE_ACCOUNT_EMAIL,key,scopes:['https://www.googleapis.com/auth/spreadsheets']});return google.sheets({version:'v4',auth})}
function cookie(req,name){return Object.fromEntries((req.headers.cookie||'').split(';').map(x=>x.trim().split('=')))[name]||''}
function sign(data){const body=Buffer.from(JSON.stringify(data)).toString('base64url');return body+'.'+crypto.createHmac('sha256',SESSION_SECRET).update(body).digest('base64url')}
function session(req){try{if(!SESSION_SECRET)return null;const [body,sig]=cookie(req,'pg_session').split('.');const good=crypto.createHmac('sha256',SESSION_SECRET).update(body).digest('base64url');if(!sig||!crypto.timingSafeEqual(Buffer.from(sig),Buffer.from(good)))return null;const data=JSON.parse(Buffer.from(body,'base64url').toString());return data.exp>Date.now()?data:null}catch{return null}}
function setSessionCookie(res,user){const secure=process.env.NODE_ENV==='production'||Boolean(process.env.RAILWAY_ENVIRONMENT);res.setHeader('Set-Cookie',`pg_session=${sign({...user,exp:Date.now()+SESSION_MAX_AGE*1000})}; HttpOnly; SameSite=Lax; Path=/; Max-Age=${SESSION_MAX_AGE}${secure?'; Secure':''}`)}
async function accessRows(){const api=sheetsClient();const meta=await api.spreadsheets.get({spreadsheetId:SHEET_ID,fields:'sheets.properties.title'});if(!(meta.data.sheets||[]).some(s=>s.properties.title===ACCESS_TAB)){await api.spreadsheets.batchUpdate({spreadsheetId:SHEET_ID,requestBody:{requests:[{addSheet:{properties:{title:ACCESS_TAB}}}]}})}const out=await api.spreadsheets.values.get({spreadsheetId:SHEET_ID,range:`'${ACCESS_TAB}'!A:F`});return out.data.values||[]}
async function accessFor(email){const rows=await accessRows();const found=rows.slice(1).find(r=>(r[0]||'').toLowerCase()===email.toLowerCase());return found?{email:found[0],name:found[1],status:(found[2]||'pending').toLowerCase(),requestedAt:found[3],updatedAt:found[4],lastLogin:found[5]}:null}
async function saveRequest(user){const api=sheetsClient(),rows=await accessRows(),now=new Date().toISOString();if(!rows.length)await api.spreadsheets.values.update({spreadsheetId:SHEET_ID,range:`'${ACCESS_TAB}'!A1:F1`,valueInputOption:'RAW',requestBody:{values:[['Email','Name','Status','Requested At','Updated At','Last Login']]}});const index=rows.slice(1).findIndex(r=>(r[0]||'').toLowerCase()===user.email);if(index<0)await api.spreadsheets.values.append({spreadsheetId:SHEET_ID,range:`'${ACCESS_TAB}'!A:F`,valueInputOption:'RAW',insertDataOption:'INSERT_ROWS',requestBody:{values:[[user.email,user.name,'pending',now,now,now]]}});else await api.spreadsheets.values.update({spreadsheetId:SHEET_ID,range:`'${ACCESS_TAB}'!F${index+2}`,valueInputOption:'RAW',requestBody:{values:[[now]]}})}
async function requireUser(req,res,next){const s=session(req);if(!s)return res.status(401).json({error:'Sign in required'});const access=await accessFor(s.email).catch(()=>null);if(!access||!['approved','admin'].includes(access.status))return res.status(403).json({error:'Access is not approved'});req.user={...s,status:access.status};next()}

app.get('/api/config',(_req,res)=>res.json({clientId:CLIENT_ID,configured:Boolean(CLIENT_ID&&ADMIN_EMAIL&&SESSION_SECRET&&process.env.GOOGLE_SERVICE_ACCOUNT_EMAIL&&process.env.GOOGLE_PRIVATE_KEY)}));
app.get('/api/me',async(req,res)=>{const s=session(req);if(!s)return res.status(401).json({user:null});const a=await accessFor(s.email).catch(()=>null),user={email:s.email,name:s.name,status:a?.status||'pending',admin:s.email===ADMIN_EMAIL||a?.status==='admin'};setSessionCookie(res,{email:s.email,name:s.name});res.json({user})});
app.post('/api/auth/google',async(req,res)=>{try{if(!CLIENT_ID||!SESSION_SECRET)throw Error('Google authentication is not configured');const ticket=await oauth.verifyIdToken({idToken:req.body.credential,audience:CLIENT_ID});const p=ticket.getPayload(),user={email:p.email.toLowerCase(),name:p.name||p.email};if(user.email===ADMIN_EMAIL){const existing=await accessFor(user.email);if(!existing)await saveRequest(user);const rows=await accessRows(),idx=rows.slice(1).findIndex(r=>(r[0]||'').toLowerCase()===user.email);if(idx>=0)await sheetsClient().spreadsheets.values.update({spreadsheetId:SHEET_ID,range:`'${ACCESS_TAB}'!C${idx+2}`,valueInputOption:'RAW',requestBody:{values:[['admin']]}})}else await saveRequest(user);const access=await accessFor(user.email);setSessionCookie(res,user);res.json({user:{...user,status:user.email===ADMIN_EMAIL?'admin':access?.status||'pending',admin:user.email===ADMIN_EMAIL}})}catch(e){res.status(401).json({error:e.message})}});
app.post('/api/logout',(_req,res)=>{res.setHeader('Set-Cookie','pg_session=; HttpOnly; SameSite=Lax; Path=/; Max-Age=0');res.json({ok:true})});
app.get('/api/admin/users',requireUser,async(req,res)=>{if(req.user.email!==ADMIN_EMAIL&&req.user.status!=='admin')return res.status(403).json({error:'Admin only'});res.json({users:(await accessRows()).slice(1).map(r=>({email:r[0],name:r[1],status:r[2],requestedAt:r[3],updatedAt:r[4],lastLogin:r[5]}))})});
app.patch('/api/admin/users/:email',requireUser,async(req,res)=>{if(req.user.email!==ADMIN_EMAIL&&req.user.status!=='admin')return res.status(403).json({error:'Admin only'});const allowed=['approved','rejected','revoked','pending'];if(!allowed.includes(req.body.status))return res.status(400).json({error:'Invalid status'});const rows=await accessRows(),idx=rows.slice(1).findIndex(r=>(r[0]||'').toLowerCase()===req.params.email.toLowerCase());if(idx<0)return res.status(404).json({error:'User not found'});await sheetsClient().spreadsheets.values.update({spreadsheetId:SHEET_ID,range:`'${ACCESS_TAB}'!C${idx+2}:E${idx+2}`,valueInputOption:'RAW',requestBody:{values:[[req.body.status,'',new Date().toISOString()]]}});res.json({ok:true})});

function parseCSV(text) {
  const rows=[]; let row=[], field='', quoted=false;
  for(let i=0;i<text.length;i++){const c=text[i],n=text[i+1];if(c==='"'&&quoted&&n==='"'){field+='"';i++}else if(c==='"')quoted=!quoted;else if(c===','&&!quoted){row.push(field);field=''}else if((c==='\n'||c==='\r')&&!quoted){if(c==='\r'&&n==='\n')i++;row.push(field);field='';if(row.some(v=>v.trim()))rows.push(row);row=[]}else field+=c}
  if(field||row.length){row.push(field);rows.push(row)} const headers=(rows.shift()||[]).map(h=>h.trim());
  return rows.map(r=>Object.fromEntries(headers.map((h,i)=>[h,(r[i]||'').trim()])));
}

app.get('/api/directory',requireUser,async(_req,res)=>{const url=`https://docs.google.com/spreadsheets/d/${SHEET_ID}/export?format=csv&gid=${GID}`;try{const response=await fetch(url,{headers:{'User-Agent':'ManagingDirectory/2.0'},signal:AbortSignal.timeout(12000)});if(!response.ok)throw Error(`Google Sheets returned ${response.status}`);const text=await response.text();if(/<!doctype html|<html/i.test(text))throw Error('Sheet is not publicly readable');res.set('Cache-Control','private, max-age=60').json({rows:parseCSV(text),source:'live',updatedAt:new Date().toISOString()})}catch(error){res.status(502).json({error:'Directory data is temporarily unavailable.',detail:error.message})}});

